"use client";
import { Copy, Activity, Pill, Clock, Beaker } from 'lucide-react';
import AIDiagnosisTool from '../medical/AIDiagnosisTool';
import TelemedicineConsult from '../telemedicine/TelemedicineConsult';
import { useHMSApi } from '@/hooks/useHMSApi';
import { useHMS } from '@/context/HMSContext';
import { useState } from 'react';

export default function DoctorDashboard() {
  const { callApi, loading } = useHMSApi();
  const { notify } = useHMS();

  const handlePrescribe = async () => {
    try {
      await callApi('/pharmacy/prescription', 'POST', {
        patientId: 'MOCK-PATIENT-001',
        doctorId: 'MOCK-DOCTOR-001',
        drugId: 'MOCK-DRUG-001',
        dosage: '1 tab daily for 7 days'
      });
      notify('SUCCESS', 'Prescription successfully drafted and sent to Pharmacy.');
    } catch (e) {
      // Handled by useHMSApi
    }
  };

  const handleOrderLab = async (testType: string = 'Full Blood Count') => {
    try {
      await callApi('/lab/order', 'POST', {
        patientId: 'MOCK-PATIENT-001',
        type: testType,
        priority: 'URGENT'
      });
      notify('SUCCESS', `Diagnostic request for ${testType} has been dispatched.`);
    } catch (e) {
      // Handled by useHMSApi
    }
  };
  return (
    <div className="space-y-12">
      <h2 className="text-4xl font-black text-slate-800 mb-8 tracking-tight">Clinical Workstation</h2>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition-all hover:-translate-y-1 group">
          <h3 className="text-slate-400 font-bold mb-2 uppercase tracking-[0.2em] text-[10px]">Today's Patients</h3>
          <p className="text-5xl font-black text-indigo-600 mt-2 group-hover:scale-110 transition-transform origin-left">12</p>
        </div>
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition-all hover:-translate-y-1 group">
          <h3 className="text-slate-400 font-bold mb-2 uppercase tracking-[0.2em] text-[10px]">Pending Reports</h3>
          <p className="text-5xl font-black text-indigo-600 mt-2 group-hover:scale-110 transition-transform origin-left">4</p>
        </div>
        <div className="bg-white p-8 rounded-3xl shadow-sm border border-slate-100 flex flex-col justify-between hover:shadow-md transition-all hover:-translate-y-1 group">
          <h3 className="text-slate-400 font-bold mb-2 uppercase tracking-[0.2em] text-[10px]">Surgical Schedule</h3>
          <p className="text-5xl font-black text-indigo-600 mt-2 group-hover:scale-110 transition-transform origin-left">1</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
         <AIDiagnosisTool />
         <div className="space-y-8">
            <TelemedicineConsult />
            <div className="bg-gradient-to-br from-indigo-600 to-purple-600 rounded-[2.5rem] p-10 text-white shadow-xl overflow-hidden relative">
               <div className="absolute top-0 right-0 w-64 h-64 bg-white/10 rounded-full blur-3xl"></div>
               <div className="relative z-10">
                  <h3 className="text-2xl font-black mb-3 inline-flex items-center gap-3"><Pill size={24} /> E-Prescription Gateway</h3>
                  <p className="text-indigo-100 font-medium max-w-xl leading-relaxed mb-8">
                    Securely transmit prescriptions directly to the hospital's central pharmacy. Helps mitigate shrinkage and avoids manual prescription errors.
                  </p>
                  <button 
                    onClick={handlePrescribe}
                    disabled={loading}
                    className={`bg-white text-indigo-600 hover:bg-gray-50 px-8 py-4 rounded-2xl font-black shadow-lg transition-all hover:-translate-y-1 hover:shadow-xl whitespace-nowrap ${loading ? 'opacity-50 cursor-not-allowed' : ''}`}
                  >
                    {loading ? 'Transmitting...' : 'Draft New E-Prescription'}
                  </button>
               </div>
            </div>

            <div className="bg-white border border-indigo-100 rounded-[2.5rem] p-10 shadow-sm relative overflow-hidden group">
               <div className="absolute -right-4 -bottom-4 opacity-5 group-hover:scale-110 transition-transform duration-500">
                  <Beaker size={160} className="text-indigo-600" />
               </div>
               <div className="relative z-10">
                  <h3 className="text-2xl font-black text-slate-800 mb-3 inline-flex items-center gap-3"><Beaker size={24} className="text-indigo-600" /> Lab Investigations</h3>
                  <p className="text-slate-500 font-medium max-w-xl leading-relaxed mb-8">
                    Order diagnostic tests and track real-time result availability. Connected directly to the LIS (Laboratory Information System).
                  </p>
                  <div className="flex gap-4">
                    <button 
                      onClick={() => handleOrderLab('Full Blood Count')}
                      disabled={loading}
                      className={`bg-indigo-600 text-white hover:bg-indigo-700 px-8 py-4 rounded-2xl font-black shadow-lg transition-all hover:-translate-y-1 hover:shadow-xl whitespace-nowrap ${loading ? 'opacity-50 cursor-not-allowed' : ''}`}
                    >
                      Order FBC
                    </button>
                    <button 
                      onClick={() => handleOrderLab('Urinalysis')}
                      disabled={loading}
                      className={`bg-slate-100 text-slate-600 hover:bg-slate-200 px-8 py-4 rounded-2xl font-black transition-all hover:-translate-y-1 whitespace-nowrap ${loading ? 'opacity-50 cursor-not-allowed' : ''}`}
                    >
                      Urinalysis
                    </button>
                  </div>
               </div>
            </div>
         </div>
      </div>
    </div>
  );
}

"use client";
import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Beaker, Search, Filter, ClipboardList, CheckCircle2, Clock, FileText, ChevronRight, PieChart } from 'lucide-react';
import { useHMSApi } from '@/hooks/useHMSApi';
import { useHMS } from '@/context/HMSContext';

const MOCK_LAB_ORDERS = [
  { id: "LAB-001", patient: "John Doe", type: "Full Blood Count", status: "PENDING", doctor: "Dr. Smith", priority: "URGENT" },
  { id: "LAB-002", patient: "Jane Smith", type: "Lipid Profile", status: "IN_PROGRESS", doctor: "Dr. Adams", priority: "ROUTINE" },
  { id: "LAB-003", patient: "Robert Brown", type: "Urinalysis", status: "COMPLETED", doctor: "Dr. Taylor", priority: "URGENT" },
  { id: "LAB-004", patient: "Alice Cooper", type: "X-Ray Chest", status: "PENDING", doctor: "Dr. Smith", priority: "ROUTINE" },
];

export default function LabManagementDashboard() {
  const [filter, setFilter] = useState('ALL');
  const { callApi, loading } = useHMSApi();
  const { notify } = useHMS();

  const handleUploadResult = async () => {
    try {
      await callApi('/lab/LAB-001/result', 'POST', {
        result: 'MOCK-RESULT-DATA-POSITIVE',
        status: 'COMPLETED'
      });
      notify('SUCCESS', 'Diagnostic report successfully uploaded and attached to Patient EHR.');
    } catch (e) {
      // Handled by useHMSApi
    }
  };

  return (
    <div className="space-y-8">
      {/* Header & Stats */}
      <div className="flex flex-col md:flex-row justify-between items-start gap-8">
        <div>
          <h2 className="text-4xl font-black text-slate-800 tracking-tight flex items-center gap-4">
             <div className="bg-indigo-600 p-4 rounded-3xl shadow-xl shadow-indigo-100 ring-8 ring-indigo-50/50">
                <Beaker className="text-white" size={32} />
             </div>
             Lab Command Center
          </h2>
          <p className="text-slate-500 font-medium mt-2 pl-20 italic">Precision diagnostics and real-time result management</p>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-3 gap-4 w-full md:w-auto">
           <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex flex-col items-center">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Pending</span>
              <span className="text-3xl font-black text-indigo-600">12</span>
           </div>
           <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm flex flex-col items-center">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Queue Time</span>
              <span className="text-3xl font-black text-emerald-600">14m</span>
           </div>
           <div className="bg-slate-900 p-6 rounded-3xl shadow-xl flex flex-col items-center col-span-2 md:col-span-1">
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Success Rate</span>
              <span className="text-3xl font-black text-white">99%</span>
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Orders List */}
        <div className="lg:col-span-2 bg-white/80 backdrop-blur-3xl border border-indigo-100 rounded-[3rem] p-10 shadow-2xl shadow-indigo-100/50">
          <div className="flex justify-between items-center mb-10">
            <h3 className="text-2xl font-black text-slate-800 tracking-tight flex items-center gap-3">
              <ClipboardList className="text-indigo-600" size={24} />
              Diagnostic Requests
            </h3>
            <div className="flex items-center gap-2 bg-slate-100 p-1.5 rounded-2xl">
               {['ALL', 'PENDING', 'COMPLETED'].map((f) => (
                 <button 
                  key={f}
                  onClick={() => setFilter(f)}
                  className={`px-4 py-2 rounded-xl text-[10px] font-black tracking-widest transition-all ${
                    filter === f ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400 hover:text-slate-600'
                  }`}
                 >
                   {f}
                 </button>
               ))}
            </div>
          </div>

          <div className="space-y-4">
            {MOCK_LAB_ORDERS.filter(o => filter === 'ALL' || o.status === filter).map((order) => (
              <motion.div 
                key={order.id}
                whileHover={{ x: 10 }}
                className="group flex items-center justify-between p-6 rounded-[2rem] border border-slate-100 hover:border-indigo-100 hover:bg-indigo-50/20 transition-all cursor-pointer"
              >
                <div className="flex items-center gap-6">
                   <div className={`p-4 rounded-2xl ${
                     order.status === 'COMPLETED' ? 'bg-emerald-100 text-emerald-600' : 'bg-amber-100 text-amber-600'
                   }`}>
                     {order.status === 'COMPLETED' ? <CheckCircle2 size={24} /> : <Clock size={24} />}
                   </div>
                   <div>
                     <div className="flex items-center gap-3">
                        <h4 className="font-black text-lg text-slate-800">{order.patient}</h4>
                        <span className={`px-2 py-0.5 rounded-md text-[8px] font-black tracking-tighter ${
                          order.priority === 'URGENT' ? 'bg-rose-100 text-rose-600' : 'bg-slate-100 text-slate-400'
                        }`}>
                          {order.priority}
                        </span>
                     </div>
                     <p className="text-sm text-slate-400 font-medium">{order.type} • Order ID: {order.id}</p>
                   </div>
                </div>

                <div className="flex items-center gap-4">
                    <div className="text-right hidden md:block">
                       <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Requester</p>
                       <p className="text-sm font-black text-slate-600">{order.doctor}</p>
                    </div>
                    <div className="bg-slate-100 p-2 rounded-xl group-hover:bg-indigo-600 group-hover:text-white transition-all">
                       <ChevronRight size={20} />
                    </div>
                </div>
              </motion.div>
            ))}
          </div>
        </div>

        {/* Action Sidebar */}
        <div className="space-y-8">
           <div className="bg-indigo-600 rounded-[2.5rem] p-10 text-white shadow-2xl relative overflow-hidden group">
              <div className="absolute top-0 right-0 w-48 h-48 bg-white/10 rounded-full blur-3xl" />
              <h3 className="text-2xl font-black mb-4 flex items-center gap-3">
                <FileText size={24} />
                Quick Entry
              </h3>
              <p className="text-indigo-100 font-medium mb-8 text-sm leading-relaxed italic">
                Securely upload diagnostic findings and scanned laboratory reports to the Patient's Electronic Health Record.
              </p>
              <button 
                onClick={handleUploadResult}
                disabled={loading}
                className={`w-full bg-white text-indigo-600 py-5 rounded-2xl font-black shadow-xl hover:-translate-y-1 transition-all ${loading ? 'opacity-50 cursor-not-allowed' : ''}`}
              >
                {loading ? 'Processing...' : 'Upload New Result'}
              </button>
           </div>

           <div className="bg-white border border-slate-100 rounded-[2.5rem] p-10 shadow-sm">
              <h4 className="text-lg font-black text-slate-800 mb-6 flex items-center gap-3">
                <PieChart className="text-indigo-600" size={20} />
                Department Efficiency
              </h4>
              <div className="space-y-6">
                 {[
                   { label: 'Pathology', val: 94 },
                   { label: 'Radiology', val: 78 },
                   { label: 'Ophthalmology', val: 89 }
                 ].map((d, i) => (
                   <div key={i} className="space-y-2">
                      <div className="flex justify-between text-xs font-black text-slate-500 uppercase tracking-widest">
                         <span>{d.label}</span>
                         <span>{d.val}%</span>
                      </div>
                      <div className="bg-slate-100 h-2 rounded-full overflow-hidden">
                         <motion.div 
                          initial={{ width: 0 }}
                          animate={{ width: `${d.val}%` }}
                          transition={{ delay: 0.2 + (i * 0.1) }}
                          className="bg-indigo-600 h-full rounded-full shadow-sm shadow-indigo-200" 
                        />
                      </div>
                   </div>
                 ))}
              </div>
           </div>
        </div>
      </div>
    </div>
  );
}
